def sanitize_sensitive_data(data):
    """Sanitize sensitive data from logs for security"""
    if not isinstance(data, dict):
        return data
    
    sanitized = data.copy()
    sensitive_fields = ['password', 'token', 'api_key', 'secret', 'authorization', 'auth_token', 'access_token']
    
    for key in sanitized:
        if any(field in key.lower() for field in sensitive_fields):
            sanitized[key] = '[REDACTED]'
    
    return sanitized


def log_request_response(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Log incoming request
        request_id = datetime.now().strftime('%Y%m%d%H%M%S%f')
        g.request_id = request_id
        
        # Sanitize headers and body for logging
        headers_dict = dict(request.headers)
        sanitized_headers = sanitize_sensitive_data(headers_dict)
        
        request_data = None
        if request.data:
            try:
                request_data = json.loads(request.data.decode('utf-8'))
                sanitized_data = sanitize_sensitive_data(request_data)
            except:
                sanitized_data = request.data.decode('utf-8')
        else:
            sanitized_data = None
        
        app.logger.info(f"[{request_id}] Incoming Request: {request.method} {request.path}")
        app.logger.debug(f"[{request_id}] Headers: {json.dumps(sanitized_headers, indent=2)}")
        app.logger.debug(f"[{request_id}] Body: {json.dumps(sanitized_data, indent=2) if sanitized_data else 'None'}")
        app.logger.debug(f"[{request_id}] Remote Address: {request.remote_addr}")
        app.logger.debug(f"[{request_id}] User Agent: {request.user_agent}")
        
        try:
            response = f(*args, **kwargs)
            
            # Log response
            if isinstance(response, tuple):
                response_data, status_code = response
            else:
                response_data = response
                status_code = 200
            
            app.logger.info(f"[{request_id}] Response Status: {status_code}")
            app.logger.debug(f"[{request_id}] Response Data: {json.dumps(response_data if isinstance(response_data, dict) else str(response_data), indent=2)}")
            
            return response
        
        except Exception as e:
            app.logger.error(f"[{request_id}] Error: {str(e)}")
            app.logger.error(f"[{request_id}] Traceback: {traceback.format_exc()}")
            raise
    
    return decorated_function


